//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = async function(inObj, pairObj, disGubun, isCode) {

    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (! await $c.gus.cfCanOpenPopup(inObj, pairObj))
        return;

    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');

}


//-------------------------------------------------------------------------
// 팝업창 처리
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
    let rtnList = new Array();

    switch (disGubun) {
        case 1:

            // 라인코드팝업			
            udc_line.cfCommonPopUp(
                scwin.udc_Line_CallBack
                ,pCode.trim()
                ,pName
                ,pClose
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,pAllSearch
                ,null);				


            break;

        case 2:

            //청구담당자코드팝업			  			
            udc_mod.cfCommonPopUp(
                scwin.udc_Mod_CallBack
                ,pCode.trim()
                ,pName
                ,pClose
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,pAllSearch
                ,null); 

            break;										

        case 3:

            //청구부서코드팝업			
            udc_bilgLodept.cfCommonPopUp(
                scwin.udc_bilgLodept_CallBack
                ,pCode.trim()
                ,pName
                ,pClose
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,null
                ,pAllSearch
                ,null);

            break;						

        default:
            break;
    }	


}

